const input = $input.first().json;
const text = input.text || input.data || '';

const maxLength = 8000;
const chunks = [];

for (let i = 0; i < text.length; i += maxLength) {
  chunks.push(text.slice(i, i + maxLength));
}

return chunks.map((chunk, index) => ({
  json: {
    chunk_id: index + 1,
    content: chunk,
    chars: chunk.length
  }
}));

const results = [];

for (const item of $input.all()) {
  const raw = item.json.output?.[0]?.content?.[0]?.text || '';

  const cleaned = raw
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  if (!cleaned || cleaned === 'null') {
    continue;
  }

  let products;

  try {
    products = JSON.parse(cleaned);
  } catch (e) {
    continue;
  }

  if (!Array.isArray(products)) {
    continue;
  }

  for (const product of products) {
    results.push({
      json: {
        name: product.name || null,
        category: product.category || null,
        description: product.description || null,
      }
    });
  }
}

return results;

function getNested(obj, path) {
  return path.split('.').reduce((acc, key) => acc?.[key], obj);
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;

  const cleaned = String(value)
    .replace(',', '.')
    .replace(/[^\d.-]/g, '');

  if (!cleaned) return null;

  const num = Number(cleaned);
  return Number.isFinite(num) ? num : null;
}

return $input.all().map(item => {
  const data = item.json;
  const desc = data.description || {};

  return {
    json: {
      name: data.name || null,
      category: data.category || null,

      calories: toNumber(desc.calories),
      proteins: toNumber(desc.proteins),
      fats: toNumber(desc.fats),
      carbohydrates: toNumber(desc.carbohydrates),

      calories_raw: desc.calories || null,
      proteins_raw: desc.proteins || null,
      fats_raw: desc.fats || null,
      carbohydrates_raw: desc.carbohydrates || null,

      raw_data: data
    }
  };
});
